from .base import Handler


class AuthHandler(Handler):
    """Handler that validates authentication tokens."""

    name = "auth"

    def __init__(self):
        self.request_log = []

    def handle(self, request):
        token = request.get("token")
        if not token:
            return {"error": "unauthorized"}
        self.request_log.append(token)
        return request

