from .base import Handler


class RequestRouter:
    """Routes incoming requests to the appropriate handler."""

    def __init__(self):
        self._handlers = {}

    def register(self, request_type, handler):
        """Register a handler for a specific request type."""
        if not isinstance(handler, Handler):
            raise TypeError("handler must be a Handler subclass")
        self._handlers[request_type] = handler

    def dispatch(self, item):
        """Dispatch an item to the correct handler based on its type field."""
        request_type = item.get("type", "default")
        handler = self._handlers.get(request_type)
        if handler is None:
            return {"error": f"no handler for type: {request_type}"}
        return handler.handle(item)

    def list_types(self):
        return list(self._handlers.keys())

