class HandlerPipeline:
    """Chains multiple handlers into a sequential processing pipeline.

    Accepts any object with a handle() method (duck typing).
    """

    def __init__(self):
        self._stages = []

    def add(self, stage):
        """Add a handler stage to the pipeline."""
        self._stages.append(stage)
        return self

    def run(self, item):
        """Run the item through all pipeline stages."""
        result = item
        for stage in self._stages:
            result = stage.handle(result)
            if result is None or "error" in result:
                break
        return result

    def stage_count(self):
        return len(self._stages)

