"""Custom exceptions for the handler system."""


class HandlerError(Exception):
    """Base exception for handler errors."""
    pass


class ValidationError(HandlerError):
    """Raised when request validation fails."""

    def __init__(self, field_name, message="missing required field"):
        self.field_name = field_name
        super().__init__(f"{message}: {field_name}")


class AuthenticationError(HandlerError):
    """Raised when authentication fails."""
    pass
